text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        "팀의 목표는 이번 주 내 Theme Package 릴리즈 준비 완료로 합의됨.",
        "공개 릴리즈는 Smoke 테스트 통과를 전제로 금요일 15:00 KST를 최종 목표 시간으로 확정.",
        "packageName mismatch가 발생하면 무시하지 않고 패키지 설정을 우선 확인하며, 계약(정의/설정)이 잘못된 경우에만 스크립트를 재검토."
      ],
      "rejected_proposals": [
        "Hara가 제안한 `smoke-theme-pack.mjs`의 packageName mismatch 무시 처리 제안은 거부.",
        "수요일 공개 릴리즈 제안은 최종 일정이 아닌 내부 stretch goal로 한정됨."
      ],
      "internal_stretch_goals": [
        "수요일 릴리즈 목표: 내부 stretch goal로만 유지."
      ]
    },
    "non_decisions": [
      "README 설치 스텝 리뷰는 '목요일 가능하면'으로 제안되었으나, 담당자와 최종 기한은 합의되지 않음.",
      "Hara의 tarball 경로 확인은 Minjun 결과 공유 이후 수행 예정이지만, 최종 마감 시간은 합의되지 않음."
    ],
    "risks": [
      "생성된 tarball 경로가 잘못되면 릴리즈가 지연될 수 있음.",
      "README 설치 단계가 오래된 경우, 릴리즈 노트가 사용자에게 오도된 정보를 전달할 수 있음."
    ],
    "open_questions": [
      "최종 릴리즈 승인 권한자는 누구인가?",
      "내부 stretch goal(수요일)을 릴리즈 노트에 명시할지 여부는 미결정."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "Smoke 테스트를 금요일 10:00 KST까지 다시 실행하고 결과를 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 Smoke 결과 공유 후 생성된 tarball 경로 점검",
      "due": "미정(미준 공유 후)",
      "status": "보류(조건부)",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README 설치 스텝 리뷰 수행",
      "due": "목표: 목요일(가능한 경우)",
      "status": "미확정",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST까지 Minjun의 Smoke 재실행 결과 수신",
      "Smoke 통과 여부 기반으로 금요일 15:00 KST 공개 릴리즈 진행 판정",
      "Doyun의 실패 트리아지 노트 작성 완료 여부",
      "Hara의 tarball 경로 확인 결과 수집",
      "README 검토 담당자 지정 및 목요일 대상 완료 여부 정리"
    ],
    "what_not_to_invent": [
      "고객명, 예산, 보안 이슈, 장애 발생, 법무 승인 요건 등 미기재 항목은 임의 추론 금지",
      "README owner/마감일, 승인권자, 릴리즈 노트 포함 항목의 최종 정책은 회의에서 추가 확정 전 가정 금지"
    ]
  },
  "non_invention_rules": [
    "회의록에 없는 고객/외부 파트너 정보는 작성하지 않는다.",
    "회의록에 없는 예산 수치, 보안 사건, 운영 중단, 법적 승인, 법무 제약은 추가하지 않는다.",
    "미확정된 owner·기한은 '미지정/미정'으로만 표기하고 임의로 채우지 않는다.",
    "수치/일정/의사결정은 원문 근거를 넘어 확장하지 않는다.",
    "열린 질문(승인 권한자, 릴리즈 노트 문구)은 답변으로 채우지 않고 질문 상태로 유지한다."
  ]
}
